  "inlineSchema": "// 学園祭実行委員会サイト - データベーススキーマ\n// 本番: PostgreSQL (Vercel Postgres / Neon 等)\n// 開発: DATABASE_URL に postgresql:// を指定\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nmodel User {\n  id            String   @id @default(cuid())\n  email         String   @unique\n  passwordHash  String?\n  name          String?\n  role          Role     @default(MEMBER)\n  profileImage  String?\n  bio           String?\n  department    String?\n  snsLinks      String? // JSON: { twitter, instagram, etc }\n  contactPublic Boolean  @default(false)\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  chairpersons     Chairperson[]\n  committeeMembers CommitteeMember[]\n  universityRoles  UniversityRole[]\n}\n\nenum Role {\n  VIEWER\n  MEMBER\n  EXECUTIVE\n  CHAIRPERSON\n  SYSTEM_ADMIN\n}\n\nmodel University {\n  id            String   @id @default(cuid())\n  name          String\n  slug          String   @unique\n  description   String?\n  logoUrl       String?\n  coverImageUrl String? // カード表示用の画像（新着大学セクションなど）\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n\n  festivals        Festival[]\n  universityRoles  UniversityRole[]\n  committeeMembers CommitteeMember[]\n}\n\nmodel Festival {\n  id           String   @id @default(cuid())\n  universityId String\n  year         Int\n  status       String   @default(\"draft\") // draft, published, archived\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  university         University          @relation(fields: [universityId], references: [id], onDelete: Cascade)\n  chairperson        Chairperson?\n  theme              Theme?\n  sponsorPlans       SponsorPlan[]\n  festivalHighlights FestivalHighlight[]\n}\n\nmodel FestivalHighlight {\n  id           String   @id @default(cuid())\n  festivalId   String\n  title        String\n  description  String?\n  imageUrl     String?\n  displayOrder Int      @default(0)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  festival Festival @relation(fields: [festivalId], references: [id], onDelete: Cascade)\n}\n\nmodel Chairperson {\n  id              String    @id @default(cuid())\n  festivalId      String    @unique\n  userId          String\n  predecessorId   String?\n  handoverDate    DateTime?\n  handoverComment String?\n  message         String?\n  displayOrder    Int       @default(0)\n  createdAt       DateTime  @default(now())\n  updatedAt       DateTime  @updatedAt\n\n  festival    Festival      @relation(fields: [festivalId], references: [id], onDelete: Cascade)\n  user        User          @relation(fields: [userId], references: [id], onDelete: Cascade)\n  predecessor Chairperson?  @relation(\"Succession\", fields: [predecessorId], references: [id])\n  successors  Chairperson[] @relation(\"Succession\")\n}\n\nmodel Theme {\n  id           String    @id @default(cuid())\n  festivalId   String    @unique\n  themeName    String\n  eventDate    DateTime?\n  eventEndDate DateTime?\n  venue        String?\n  schedule     String? // JSON or markdown\n  details      String?\n  accessInfo   String?\n  createdAt    DateTime  @default(now())\n  updatedAt    DateTime  @updatedAt\n\n  festival Festival @relation(fields: [festivalId], references: [id], onDelete: Cascade)\n}\n\nmodel SponsorPlan {\n  id           String   @id @default(cuid())\n  festivalId   String\n  planName     String\n  amount       Int // 協賛金額（円）\n  benefits     String? // 特典説明（markdown可）\n  displayOrder Int      @default(0)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  festival Festival @relation(fields: [festivalId], references: [id], onDelete: Cascade)\n}\n\nmodel CommitteeMember {\n  id           String   @id @default(cuid())\n  userId       String\n  universityId String\n  role         Role     @default(MEMBER)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  user       User       @relation(fields: [userId], references: [id], onDelete: Cascade)\n  university University @relation(fields: [universityId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, universityId])\n}\n\nmodel UniversityRole {\n  id           String   @id @default(cuid())\n  userId       String\n  universityId String\n  role         Role\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  user       User       @relation(fields: [userId], references: [id], onDelete: Cascade)\n  university University @relation(fields: [universityId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, universityId])\n}\n\n// 学祭がくれたもの - 取材オファー（招待制）\nmodel GakusaiInterviewOffer {\n  id              String    @id @default(cuid())\n  inviteToken     String    @unique\n  chairpersonName String\n  university      String\n  year            Int\n  status          String    @default(\"pending\") // pending, in_progress, completed\n  conversation    String? // JSON: [{ role: \"ai\"|\"user\", content: string }]\n  articleId       String?\n  expiresAt       DateTime?\n  createdAt       DateTime  @default(now())\n  updatedAt       DateTime  @updatedAt\n}\n\n// 学祭がくれたもの - AI取材記事\nmodel GakusaiArticle {\n  id              String    @id @default(cuid())\n  title           String\n  excerpt         String\n  chairpersonName String\n  university      String\n  year            Int\n  thumbnailUrl    String\n  status          String    @default(\"draft\") // draft, published\n  publishedAt     DateTime?\n  createdAt       DateTime  @default(now())\n  updatedAt       DateTime  @updatedAt\n\n  sections GakusaiArticleSection[]\n}\n\nmodel GakusaiArticleSection {\n  id           String   @id @default(cuid())\n  articleId    String\n  heading      String\n  content      String\n  imageUrl     String? // セクション用の写真（任意）\n  displayOrder Int      @default(0)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  article GakusaiArticle @relation(fields: [articleId], references: [id], onDelete: Cascade)\n}\n"
